                    <h2 id="endpoints-GETapi-stock-ledger">Get stock ledger list with optional filters.</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Returns a list of stock ledger transactions based on the provided filters.</p>

<span id="example-requests-GETapi-stock-ledger">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request GET \
    --get "http://sitepilot/api/stock-ledger?project_id=16&amp;material_id=16&amp;type=architecto&amp;start_date=architecto&amp;end_date=architecto" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"project_id\": 16,
    \"material_id\": 16,
    \"type\": \"opening\",
    \"start_date\": \"2026-05-09T17:30:01\",
    \"end_date\": \"2052-06-01\"
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://sitepilot/api/stock-ledger"
);

const params = {
    "project_id": "16",
    "material_id": "16",
    "type": "architecto",
    "start_date": "architecto",
    "end_date": "architecto",
};
Object.keys(params)
    .forEach(key =&gt; url.searchParams.append(key, params[key]));

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "project_id": 16,
    "material_id": 16,
    "type": "opening",
    "start_date": "2026-05-09T17:30:01",
    "end_date": "2052-06-01"
};

fetch(url, {
    method: "GET",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

