<span id="example-requests-POSTapi-materials">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://sitepilot/api/materials" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: multipart/form-data" \
    --header "Accept: application/json" \
    --form "name=Cement"\
    --form "hsn_sac=2523"\
    --form "gst_master_id=1"\
    --form "category_id=5"\
    --form "unit_id=3"\
    --form "description=Portland cement"\
    --form "price=450"\
    --form "reorder_level=100"\
    --form "status=active"\
    --form "created_by=1"\
    --form "image=@C:\Users\ninad\AppData\Local\Temp\php5958.tmp" </code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://sitepilot/api/materials"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "multipart/form-data",
    "Accept": "application/json",
};

const body = new FormData();
body.append('name', 'Cement');
body.append('hsn_sac', '2523');
body.append('gst_master_id', '1');
body.append('category_id', '5');
body.append('unit_id', '3');
body.append('description', 'Portland cement');
body.append('price', '450');
body.append('reorder_level', '100');
body.append('status', 'active');
body.append('created_by', '1');
body.append('image', document.querySelector('input[name="image"]').files[0]);

fetch(url, {
    method: "POST",
    headers,
    body,
}).then(response =&gt; response.json());</code></pre></div>

