                    <h2 id="payment-request-POSTapi-po-advance-request--po_id-">Create PO Advance Request</h2>

<p>
<small class="badge badge-darkred">requires authentication</small>
</p>

<p>Creates a new PO advance request.
This replicates the exact business logic from PurchaseOrderController@storeAdvanceRequest.</p>

<span id="example-requests-POSTapi-po-advance-request--po_id-">
<blockquote>Example request:</blockquote>


<div class="bash-example">
    <pre><code class="language-bash">curl --request POST \
    "http://sitepilot/api/po-advance-request/architecto" \
    --header "Authorization: Bearer {YOUR_AUTH_KEY}" \
    --header "Content-Type: application/json" \
    --header "Accept: application/json" \
    --data "{
    \"percentage\": 16,
    \"advance_amount\": \"architecto\",
    \"payment_date\": \"architecto\",
    \"notes\": \"architecto\",
    \"workspace_id\": 16,
    \"site_id\": 16,
    \"po_id\": 16
}"
</code></pre></div>


<div class="javascript-example">
    <pre><code class="language-javascript">const url = new URL(
    "http://sitepilot/api/po-advance-request/architecto"
);

const headers = {
    "Authorization": "Bearer {YOUR_AUTH_KEY}",
    "Content-Type": "application/json",
    "Accept": "application/json",
};

let body = {
    "percentage": 16,
    "advance_amount": "architecto",
    "payment_date": "architecto",
    "notes": "architecto",
    "workspace_id": 16,
    "site_id": 16,
    "po_id": 16
};

fetch(url, {
    method: "POST",
    headers,
    body: JSON.stringify(body),
}).then(response =&gt; response.json());</code></pre></div>

